(function(global){
  function escapeHtml(text){
    return text
      .replace(/&/g,'&amp;')
      .replace(/</g,'&lt;')
      .replace(/>/g,'&gt;')
      .replace(/\"/g,'&quot;')
      .replace(/'/g,'&#39;');
  }

  function parseInline(text){
    var value = escapeHtml(text);
    value = value.replace(/`([^`]+)`/g,'<code>$1</code>');
    value = value.replace(/\*\*([^*]+)\*\*/g,'<strong>$1</strong>');
    value = value.replace(/__([^_]+)__/g,'<strong>$1</strong>');
    value = value.replace(/(^|[^*])\*([^*]+)\*(?!\*)/g,'$1<em>$2</em>');
    value = value.replace(/(^|[^_])_([^_]+)_(?!_)/g,'$1<em>$2</em>');
    return value;
  }

  function closeLists(state,out){
    while(state.listStack.length>0){
      out.push('</'+state.listStack.pop()+'>');
    }
  }

  function openList(tag,state,out){
    state.listStack.push(tag);
    out.push('<'+tag+'>');
  }

  function parseBlocks(lines){
    var out=[];
    var state={ inCode:false, codeLines:[], listStack:[], inBlockquote:false, quoteLines:[] };

    function flushCode(){
      if(state.inCode){
        out.push('<pre><code>'+escapeHtml(state.codeLines.join('\n'))+'</code></pre>');
        state.inCode=false;
        state.codeLines=[];
      }
    }

    function flushQuote(){
      if(state.inBlockquote){
        var inner = parseBlocks(state.quoteLines);
        out.push('<blockquote>'+inner+'</blockquote>');
        state.inBlockquote=false;
        state.quoteLines=[];
      }
    }

    for(var i=0;i<lines.length;i++){
      var line=lines[i];

      if(/^```/.test(line)){
        closeLists(state,out);
        flushQuote();
        if(state.inCode){
          flushCode();
        }else{
          state.inCode=true;
          state.codeLines=[];
        }
        continue;
      }

      if(state.inCode){
        state.codeLines.push(line);
        continue;
      }

      if(/^>\s?/.test(line)){
        closeLists(state,out);
        state.inBlockquote=true;
        state.quoteLines.push(line.replace(/^>\s?/,''));
        continue;
      } else {
        flushQuote();
      }

      if(/^\s*$/.test(line)){
        closeLists(state,out);
        continue;
      }

      if(/^---+$/.test(line) || /^\*\*\*+$/.test(line)){
        closeLists(state,out);
        out.push('<hr>');
        continue;
      }

      var heading=line.match(/^(#{1,6})\s+(.*)$/);
      if(heading){
        closeLists(state,out);
        var level=heading[1].length;
        out.push('<h'+level+'>'+parseInline(heading[2])+'</h'+level+'>');
        continue;
      }

      var uitem=line.match(/^\s*[-*+]\s+(.*)$/);
      if(uitem){
        if(state.listStack[state.listStack.length-1]!=='ul'){
          closeLists(state,out);
          openList('ul',state,out);
        }
        out.push('<li>'+parseInline(uitem[1])+'</li>');
        continue;
      }

      var oitem=line.match(/^\s*\d+\.\s+(.*)$/);
      if(oitem){
        if(state.listStack[state.listStack.length-1]!=='ol'){
          closeLists(state,out);
          openList('ol',state,out);
        }
        out.push('<li>'+parseInline(oitem[1])+'</li>');
        continue;
      }

      closeLists(state,out);
      out.push('<p>'+parseInline(line)+'</p>');
    }

    flushQuote();
    flushCode();
    closeLists(state,out);
    return out.join('');
  }

  var marked={
    parse:function(markdown){
      if(markdown===undefined || markdown===null){
        return '';
      }
      var normalized=String(markdown).replace(/\r\n/g,'\n').replace(/\r/g,'\n');
      return parseBlocks(normalized.split('\n'));
    }
  };

  global.marked=marked;
})(this);
